    # Process Battles questions (10 levels * 10 battles * 2 questions = 200 questions)
    for lvl_idx, lvl_facts in enumerate(battles_levels):
        for f_idx, fact in enumerate(lvl_facts):
            name, year, leader, opponent, result = fact
            
            # Pools for distractors from the same level
            other_leaders = [x[2] for x in lvl_facts if x[2] != leader]
            # Ensure unique list of leaders
            other_leaders = list(dict.fromkeys(other_leaders))
            while len(other_leaders) < 3:
                other_leaders.append("صلاح الدين الأيوبي" if len(other_leaders) == 1 else "خالد بن الوليد")
                
            other_results = [x[4] for x in lvl_facts if x[4] != result]
            other_results = list(dict.fromkeys(other_results))
            while len(other_results) < 3:
                other_results.append("فتح بلاد الهند والسند بالكامل ودخول ملايين الإسلام" if len(other_results) == 1 else "بناء جامعة قرطبة بالأندلس")

            # Question 1: Leader question
            opts_1 = [leader] + random.sample(other_leaders, 3)
            q_id_1 = lvl_idx * 20 + f_idx * 2 + 1
            questions.append({
                "id": f"enc_battles_{q_id_1}",
                "category": "enc_battles",
                "question": f"من هو القائد المسلم البارز الذي قاد جيوش الفتح أو الدفاع في '{name}'؟",
                "options": opts_1,
                "correctAnswerIndex": 0,
                "explanation": f"قاد البطل {leader} المسلمين في {name} وحقق فيها نصراً عظيماً وموثقاً.",
                "verseOrHadithText": f"تاريخ المعارك والفتوحات - {name}"
            })
            
            # Question 2: Result question
            opts_2 = [result] + random.sample(other_results, 3)
            q_id_2 = lvl_idx * 20 + f_idx * 2 + 2
            questions.append({
                "id": f"enc_battles_{q_id_2}",
                "category": "enc_battles",
                "question": f"ما هي النتيجة التاريخية والجيوسياسية الأبرز الموثقة لـ '{name}' ({year})؟",
                "options": opts_2,
                "correctAnswerIndex": 0,
                "explanation": f"أدت {name} ({year}) إلى {result}.",
                "verseOrHadithText": f"نتائج وآثار {name} ({year})"
            })


